   118→    }, [refreshExtractData]),
   119→  );
   120→
   121→  useEffect(() => {
   122→    const shouldFetchBalance =
   123→      pointsBalance.points === undefined ||
   124→      pointsBalance.status === PointsBalanceStatus.ERROR;
   125→
